<script setup lang="ts">
const { theme, toggleTheme } = inject('theme') as any
const sidebarOpen = ref(false)

const nav = [
  {
    group: 'Getting Started',
    to: '/getting-started',
    items: [],
  },
  {
    group: 'Foundation',
    items: [
      { label: 'Colors', to: '/tokens/colors' },
      { label: 'Typography', to: '/tokens/typography' },
      { label: 'Spacing', to: '/tokens/spacing' },
      { label: 'Radius', to: '/tokens/radius' },
      { label: 'Elevation', to: '/tokens/effects' },
      { label: 'Icons', to: '/tokens/icons' },
    ],
  },
  {
    group: 'Components',
    items: [
      { label: 'Button', to: '/components/button' },
      { label: 'Badge', to: '/components/badge' },
      // 后续新增组件在这里追加
    ],
  },
  {
    group: 'AI Components',
    items: [
      { label: 'Chain of Thought', to: '/components/ai-chain-of-thought' },
      { label: 'Reasoning', to: '/components/ai-reasoning' },
      { label: 'Markdown', to: '/components/ai-markdown' },
      // 后续新增 AI 组件在这里追加
    ],
  },
]

// Close sidebar on navigation (mobile)
const route = useRoute()
watch(() => route.path, () => {
  sidebarOpen.value = false
})

// Fade states for sidebar
const showTopFade = ref(false)
const showBottomFade = ref(false)
const sidebarRef = ref<HTMLElement | null>(null)

const updateFadeStates = () => {
  if (!sidebarRef.value) return

  const { scrollTop, scrollHeight, clientHeight } = sidebarRef.value

  // 顶部渐隐：滚动超过 10px 时显示
  showTopFade.value = scrollTop > 10

  // 底部渐隐：还有内容可以滚动时显示
  showBottomFade.value = scrollTop + clientHeight < scrollHeight - 10
}

onMounted(() => {
  updateFadeStates()
})
</script>

