          </NuxtLink>

          <!-- Theme toggle switch -->
          <button
            class="relative w-14 h-8 bg-[var(--color-mask-overlays)] transition-colors flex items-center justify-between px-2"
            style="border-radius: var(--radius-m-12);"
            :title="theme === 'light' ? 'Switch to dark mode' : 'Switch to light mode'"
            @click="toggleTheme"
          >
            <!-- Sun icon (left) -->
            <svg class="w-3.5 h-3.5 text-[var(--color-text-tertiary)] z-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <circle cx="12" cy="12" r="5" stroke-width="2" />
              <line x1="12" y1="1" x2="12" y2="3" stroke-width="2" stroke-linecap="round" />
              <line x1="12" y1="21" x2="12" y2="23" stroke-width="2" stroke-linecap="round" />
              <line x1="4.22" y1="4.22" x2="5.64" y2="5.64" stroke-width="2" stroke-linecap="round" />
              <line x1="18.36" y1="18.36" x2="19.78" y2="19.78" stroke-width="2" stroke-linecap="round" />
              <line x1="1" y1="12" x2="3" y2="12" stroke-width="2" stroke-linecap="round" />
              <line x1="21" y1="12" x2="23" y2="12" stroke-width="2" stroke-linecap="round" />
              <line x1="4.22" y1="19.78" x2="5.64" y2="18.36" stroke-width="2" stroke-linecap="round" />
              <line x1="18.36" y1="5.64" x2="19.78" y2="4.22" stroke-width="2" stroke-linecap="round" />
            </svg>

            <!-- Moon icon (right) -->
            <svg class="w-3.5 h-3.5 text-[var(--color-text-tertiary)] z-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" />
            </svg>

            <!-- Slider -->
            <div
              class="absolute top-1 w-6 h-6 bg-[var(--color-fill-surfacebright)] border border-[var(--color-border-translucent)] shadow-[var(--elevation-l1)] transition-all duration-200 ease-in-out"
              style="border-radius: var(--radius-s-8);"
              :class="theme === 'light' ? 'left-1' : 'left-[28px]'"
            />
          </button>
        </div>
      </header>

      <!-- Content area: Sidebar + Main (with top padding to avoid header) -->
      <div class="max-w-[1404px] mx-auto pt-28 px-6 flex gap-16">
        <!-- Sidebar (180px, sticky) -->
        <div class="sidebar-wrapper">
          <div v-show="showTopFade" class="sidebar-fade sidebar-fade--top"></div>
          <aside class="sidebar-nav" ref="sidebarRef" @scroll="updateFadeStates">
            <nav class="flex flex-col gap-8">
              <div v-for="section in nav" :key="section.group" class="flex flex-col gap-3">
              <!-- Group as link -->
              <NuxtLink
                v-if="section.to"
                :to="section.to"
                class="nav-group-link pl-2 transition-colors flex items-center"
                style="font-size: var(--typo-interface-desktop-body-body-large-size); line-height: var(--typo-interface-desktop-body-body-large-lh); font-weight: var(--typo-interface-desktop-body-body-large-weight); letter-spacing: var(--typo-interface-desktop-body-body-large-ls); gap: var(--spacing-size-s-8);"
                active-class="nav-group-link--active"
              >
                <svg class="nav-group-link__icon" width="20" height="20" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path fill-rule="evenodd" clip-rule="evenodd" d="M9.43959 2.94736C9.8221 2.68063 10.3324 2.68048 10.7148 2.94736L10.7942 3.00839L14.3663 6.00888V4.98959L14.379 4.86345C14.4373 4.57935 14.6888 4.36589 14.9901 4.36581H15.4808L15.607 4.37843C15.8913 4.43659 16.1054 4.68808 16.1054 4.98959V7.44606H16.0774L17.8482 8.93369C18.1118 9.15538 18.1463 9.54924 17.9247 9.813C17.7031 10.0767 17.3092 10.1106 17.0454 9.88909L16.1054 9.09929V14.9143C16.1053 16.0186 15.2098 16.9138 14.1055 16.9138H6.04847C4.94426 16.9137 4.0487 16.0185 4.04856 14.9143V9.09889L3.10821 9.88909C2.84435 10.1105 2.45047 10.0768 2.22889 9.813C2.0074 9.54915 2.04244 9.1553 2.30621 8.93369L9.35902 3.00839L9.43959 2.94736ZM9.51039 11.7356C8.89496 11.7357 8.39592 12.2347 8.39589 12.8501V15.2488C8.39589 15.4789 8.58251 15.6654 8.81255 15.6655H11.3414C11.5716 15.6655 11.7581 15.4789 11.7581 15.2488V12.8501C11.7581 12.2346 11.2583 11.7356 10.6428 11.7356H9.51039Z" fill="currentColor"/>
                </svg>
                {{ section.group }}
              </NuxtLink>
              <!-- Group as text -->
              <p v-else class="pl-2 font-bold" style="font-size: var(--typo-interface-desktop-subhead-subhead-small-size); line-height: var(--typo-interface-desktop-subhead-subhead-small-lh); letter-spacing: var(--typo-interface-desktop-subhead-subhead-small-ls);">
                {{ section.group }}
              </p>
              <!-- Items list -->
              <ul v-if="section.items.length > 0" class="flex flex-col gap-1">
                <li v-for="item in section.items" :key="item.to">
                  <NuxtLink
                    :to="item.to"
                    class="flex items-center h-8 px-2 py-1 rounded-lg text-[var(--color-text-secondary)] transition-colors hover:bg-[var(--color-mask-overlays)]"
                    style="font-size: var(--typo-interface-desktop-body-body-large-size); line-height: var(--typo-interface-desktop-body-body-large-lh); letter-spacing: var(--typo-interface-desktop-body-body-large-ls);"
                    active-class="bg-[var(--color-mask-overlaym)]"
                  >
                    {{ item.label }}
                  </NuxtLink>
                </li>
              </ul>
              </div>
            </nav>
          </aside>
          <div v-show="showBottomFade" class="sidebar-fade sidebar-fade--bottom"></div>
        </div>

        <!-- Main content (flex-1, fills remaining space) -->
        <main class="flex-1 pb-20">
          <slot />
        </main>
      </div>
    </div>

    <!-- Mobile layout -->
    <div class="flex lg:hidden flex-col min-h-[calc(100vh-56px)]">
      <!-- Sidebar overlay -->
      <Transition
        enter-active-class="transition-opacity duration-200"
        leave-active-class="transition-opacity duration-200"
        enter-from-class="opacity-0"
        leave-to-class="opacity-0"
      >
        <div
          v-if="sidebarOpen"
          class="fixed inset-0 bg-black/50 z-40"
          @click="sidebarOpen = false"
        />
      </Transition>

      <!-- Sidebar -->
      <aside
        class="fixed top-0 left-0 bottom-0 w-[180px] flex flex-col bg-[var(--color-fill-surface-desktop)] z-50 transform transition-transform duration-200"
        :class="sidebarOpen ? 'translate-x-0' : '-translate-x-full'"
      >
        <!-- Mobile header inside sidebar -->
        <div class="h-14 flex items-center justify-between px-5 border-b border-[var(--color-border-translucent)]">
          <NuxtLink to="/" class="text-sm font-semibold tracking-tight" @click="sidebarOpen = false">
            Xmind UI Kit
          </NuxtLink>
          <button
            @click="sidebarOpen = false"
            class="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-[var(--color-fill-secondary)] transition-colors"
